export interface Content11Props {
  media: {
    src: string
    alt: string
  }
  items: {
    title: string
    description: string
  }[]
}

export function Content11({
  media,
  items,
}: Readonly<Content11Props>) {
  return (
    <div className="space-y-8">
      {media && (
        <div className="relative max-h-140 min-h-96 w-full overflow-hidden rounded-lg">
          <img
            src={media.src}
            alt={media.alt ?? 'Content 11'}
            loading="lazy"
            decoding="async"
            className="absolute inset-0 size-full object-cover"
          />
        </div>
      )}

      {items && items.length > 0 && (
        <ul className="m-0 grid list-none grid-cols-1 gap-6 p-0 md:grid-cols-3">
          {items.map((item, index) => (
            <li key={`${item.title}-${index}`} className="flex flex-col gap-2">
              {item.title && (
                <h3 className="text-lg font-medium">{item.title}</h3>
              )}
              {item.description && (
                <p className="text-muted-foreground max-w-md text-sm">
                  {item.description}
                </p>
              )}
            </li>
          ))}
        </ul>
      )}
    </div>
  )
}

